svg.script:
(() => {
  const VIEW_W = 374;
const TOP_CHAIN = ["A", "L", "C", "D", "E", "R", "G"];
const BASE_HEAD = {
      cheekD: "M65 153 C97 159 136 168 172 154 C181 150 193 147 202 154 C238 168 277 159 309 153 C331 178 336 221 303 246 C270 268 104 268 71 246 C38 221 43 178 65 153Z",
      headCapD: "M64 153 C64 88 116 48 187 48 C258 48 310 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z",
      leftCreaseD: "M62 238 C70 250 84 256 100 256",
      rightCreaseD: "M312 238 C304 250 290 256 274 256"
    };
const RIGHT_HEAD_CAP_D = "M64 153 C66.12 89.55 117.55 49.81 187 48 C267.24 48 328.48 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const LEFT_HEAD_CAP_D = "M64 153 C45.52 88 106.76 48 187 48 C256.45 49.81 307.88 89.55 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const FRONT_TAIL = [
      [331, 178, 336, 221, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [38, 221, 43, 178, 65, 153]
    ];
const LEFT_TAIL = [
      [320.06, 180.73, 321.87, 218.27, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [35.12, 221, 40.60, 178, 65, 153]
    ];
const RIGHT_TAIL = [
      [333.40, 178.00, 338.88, 221.00, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [52.13, 218.27, 53.94, 180.73, 65, 153]
    ];
const PITCH_UP = {
      axis: -25.5,
      lower: 3.6,
      faceDy: -21.5,
      faceSy: 0.93,
      blushDy: -22.41,
      earDy: 12,
      tuftDy: 12
    };
const PITCH_DOWN = {
      axis: 26,
      lower: -7.9,
      faceDy: 24.5,
      faceSy: 1,
      blushDy: 24.5,
      earDy: -10,
      tuftDy: -2
    };
const HEAD_FRAME_PIVOT = { x: 187, y: 246 };
const defaults = {
      body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
      head: { yaw: 0, pitch: 0, angle: 0 },
      glasses: { x: 0, y: 0, scale: 1, rotate: 0 },
      hand: { x: 50, y: 92, scale: 0.49, rotate: -38, opacity: 0 },
      leftBubble: { x: -138, y: 52, scale: 0.48 },
      rightBubble: { x: 384, y: 62, scale: 0.49 },
      display: { showGuide: false, checkerBg: false, showBubbles: false, showHand: true }
    };
const posePresets = {
      "1": {
        body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
        head: { yaw: -21, pitch: 31, angle: 10 },
        glasses: { x: 0, y: 0, scale: 1, rotate: 0 },
        hand: { x: 50, y: 92, scale: 0.49, rotate: -22.5, opacity: 1 }
      },
      "2": {
        body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
        head: { yaw: -21, pitch: 14, angle: 10 },
        glasses: { x: 0, y: 0, scale: 1, rotate: 0 },
        hand: { x: 50, y: 92, scale: 0.49, rotate: -10, opacity: 1 }
      },
      "3": {
        body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
        head: { yaw: -21, pitch: 14, angle: 10 },
        glasses: { x: 0, y: -12, scale: 1, rotate: 0 },
        hand: { x: 50, y: 92, scale: 0.49, rotate: -7.75, opacity: 1 }
      },
      "4": {
        body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
        head: { yaw: -21, pitch: 31, angle: 10 },
        glasses: { x: 0, y: 0, scale: 1, rotate: 0 },
        hand: { x: 50, y: 92, scale: 0.49, rotate: -38, opacity: 1 }
      },
      "6": {
        body: { x: 0, y: 0, scale: 1, rotate: 0, masterHands: 1 },
        head: { yaw: 0, pitch: 0, angle: 0 },
        glasses: { x: 0, y: 0, scale: 1, rotate: 0 },
        hand: { x: 50, y: 92, scale: 0.49, rotate: -38, opacity: 0 }
      }
    };
const animationKeyframes = [
      { at: 0, pose: "6" },
      { at: 1100, pose: "6" },
      { at: 1420, pose: "1" },
      { at: 1600, pose: "2" },
      { at: 1780, pose: "3" },
      { at: 1960, pose: "2" },
      { at: 2140, pose: "3" },
      { at: 2320, pose: "2" },
      { at: 2520, pose: "1" },
      { at: 2780, pose: "4" },
      { at: 3240, pose: "6" },
      { at: 5200, pose: "6" }
    ];
const animationDuration = animationKeyframes[animationKeyframes.length - 1].at;
  const rawAnchors = {"A":{"x":65,"y":153,"label":"左边界"},"L":{"x":137.77,"y":162.56,"label":"左弧低点"},"C":{"x":171.37,"y":154.02,"label":"鼻梁左"},"D":{"x":189.69,"y":147.65,"label":"鼻梁峰"},"E":{"x":210.43,"y":157.48,"label":"鼻梁右"},"R":{"x":240.66,"y":162.63,"label":"右弧低点"},"G":{"x":309,"y":153,"label":"右边界"},"B":{"x":138,"y":157,"label":"左眼中心"},"F":{"x":237,"y":157,"label":"右眼中心"},"N":{"x":187,"y":170,"label":"鼻中心"},"J":{"x":187,"y":177,"label":"鼻下"},"ML":{"x":163,"y":192,"label":"嘴左端"},"MR":{"x":211,"y":192,"label":"嘴右端"},"BL":{"x":92,"y":185,"label":"左腮红"},"BR":{"x":281,"y":185,"label":"右腮红"},"H":{"x":187,"y":48,"label":"头顶"},"T":{"x":203,"y":16,"label":"呆毛"},"EL":{"x":101,"y":73,"label":"左耳"},"ER":{"x":286,"y":73,"label":"右耳"},"LS":{"x":62,"y":238,"label":"左腮影起"},"LC1":{"x":70,"y":250,"label":"左腮影控1"},"LC2":{"x":84,"y":256,"label":"左腮影控2"},"LE":{"x":100,"y":256,"label":"左腮影止"},"RS":{"x":312,"y":238,"label":"右腮影起"},"RC1":{"x":304,"y":250,"label":"右腮影控1"},"RC2":{"x":290,"y":256,"label":"右腮影控2"},"RE":{"x":274,"y":256,"label":"右腮影止"},"ELR":{"x":88,"y":102,"label":"左耳根"},"ELC":{"x":101,"y":73,"label":"左耳心"},"ELI":{"x":101,"y":73,"label":"左内耳"},"ERR":{"x":274,"y":102,"label":"右耳根"},"ERC":{"x":286,"y":73,"label":"右耳心"},"ERI":{"x":286,"y":73,"label":"右内耳"},"TLR":{"x":182,"y":49,"label":"左呆毛根"},"TLC":{"x":184,"y":35,"label":"左呆毛控"},"TLT":{"x":192,"y":15,"label":"左呆毛尖"},"TRR":{"x":200,"y":50,"label":"右呆毛根"},"TRC":{"x":203,"y":34,"label":"右呆毛控"},"TRT":{"x":214,"y":16,"label":"右呆毛尖"}};
  let state = poseState("6");
  let rafId = null;
  let paused = false;
  let loopStartTime = performance.now();

  const stageSvg = document.currentScript && document.currentScript.ownerSVGElement;
  if (!stageSvg) return;
  const masterLayer = stageSvg.querySelector("#hamsterMasterLayer");
  const handLayer = stageSvg.querySelector("#handLayer");
  const headFrameLayer = stageSvg.querySelector("#working-2session-head-motion-layer");

  setProgress(0);
  const reduceMotion = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  if (!reduceMotion) play();

  window.__cloudlingIdleGlassesPush = { play, pause, replay, setProgress, snapshot };
  window.__cloudlingReplayIdleGlassesPush = replay;
  window.__cloudlingSetIdleGlassesPushProgress = setProgress;
  window.__clawdSetLowPowerPaused = (value) => {
    paused = Boolean(value);
    if (paused) pause();
    else if (!reduceMotion) play();
  };

  function play() {
    paused = false;
    if (rafId !== null) return;
    rafId = requestAnimationFrame(tick);
  }

  function pause() {
    paused = true;
    if (rafId !== null) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
  }

  function replay() {
    loopStartTime = performance.now();
    setProgress(0);
    play();
  }

  function tick(now) {
    if (paused) {
      rafId = null;
      return;
    }
    const progress = ((now - loopStartTime) % animationDuration) / animationDuration;
    setProgress(progress);
    rafId = requestAnimationFrame(tick);
  }

  function setProgress(progress) {
    const wrapped = ((Number(progress) || 0) % 1 + 1) % 1;
    state = animationStateAt(wrapped * animationDuration);
    render();
  }

  function snapshot() {
    return JSON.parse(JSON.stringify(state));
  }

  function render() {
    masterLayer.setAttribute("transform", `translate(${fmt(state.body.x)} ${fmt(state.body.y)}) rotate(${fmt(state.body.rotate)} 187 230) scale(${fmt(state.body.scale)} ${fmt(state.body.scale)})`);
    handLayer.setAttribute("transform", `translate(${fmt(state.hand.x)} ${fmt(state.hand.y)}) rotate(${fmt(state.hand.rotate)} 86 162) scale(${fmt(state.hand.scale)} ${fmt(state.hand.scale)})`);
    handLayer.setAttribute("opacity", state.display.showHand ? fmt(state.hand.opacity) : "0");

    const importedHands = masterLayer.querySelector("#hands-layer");
    if (importedHands) importedHands.setAttribute("opacity", "0");
    const confirmedBackHands = masterLayer.querySelector("#confirmed-idle-back-hands-layer");
    const confirmedBackHandShadows = masterLayer.querySelector("#confirmed-idle-back-hand-shadows-layer");
    const confirmedBackHandLeft = masterLayer.querySelector("#confirmed-idle-back-hand-left-layer");
    const confirmedBackHandRight = masterLayer.querySelector("#confirmed-idle-back-hand-right-layer");
    const confirmedBackHandShadowLeft = masterLayer.querySelector("#confirmed-idle-back-hand-shadow-left-layer");
    const confirmedBackHandShadowRight = masterLayer.querySelector("#confirmed-idle-back-hand-shadow-right-layer");
    const backHandOpacity = clamp(state.body.masterHands, 0, 1);
    const pastedHandOpacity = state.display.showHand ? clamp(state.hand.opacity, 0, 1) : 0;
    const replacedBackHandOpacity = backHandOpacity * (1 - pastedHandOpacity);
    if (confirmedBackHands) confirmedBackHands.setAttribute("opacity", "1");
    if (confirmedBackHandShadows) confirmedBackHandShadows.setAttribute("opacity", "1");
    if (confirmedBackHandLeft) confirmedBackHandLeft.setAttribute("opacity", fmt(replacedBackHandOpacity));
    if (confirmedBackHandShadowLeft) confirmedBackHandShadowLeft.setAttribute("opacity", fmt(replacedBackHandOpacity));
    if (confirmedBackHandRight) confirmedBackHandRight.setAttribute("opacity", fmt(backHandOpacity));
    if (confirmedBackHandShadowRight) confirmedBackHandShadowRight.setAttribute("opacity", fmt(backHandOpacity));

    renderHeadLook();
  }

  function animationStateAt(time) {
    let prev = animationKeyframes[0];
    let next = animationKeyframes[animationKeyframes.length - 1];
    for (let i = 0; i < animationKeyframes.length - 1; i += 1) {
      const a = animationKeyframes[i];
      const b = animationKeyframes[i + 1];
      if (time >= a.at && time <= b.at) {
        prev = a;
        next = b;
        break;
      }
    }
    const duration = Math.max(1, next.at - prev.at);
    const t = smooth01((time - prev.at) / duration);
    return interpolateState(poseState(prev.pose), poseState(next.pose), t);
  }

  function poseState(pose) {
    return mergeState(clone(defaults), posePresets[pose] || {});
  }

  function interpolateState(a, b, t) {
    const out = clone(a);
    for (const group of Object.keys(out)) {
      if (!b[group] || typeof out[group] !== "object") continue;
      for (const key of Object.keys(out[group])) {
        const av = out[group][key];
        const bv = b[group][key];
        out[group][key] = typeof av === "number" && typeof bv === "number"
          ? lerp(av, bv, t)
          : (t < 0.5 ? av : bv);
      }
    }
    return out;
  }

function renderHeadLook() {
      if (!headFrameLayer) return;
      const lookActive = headLookActive();
      const cheek = cheekPath();
      const elem = elementOffsets();
      const ears = earState();

      setAttr("head-cap-fill", "d", headCapPath());
      setAttr("cheek-muzzle-fill", "d", cheek);
      setAttr("idle-look-blush-clip-path", "d", cheek);
      setAttr("left-cheek-crease", "d", creasePath("left"));
      setAttr("right-cheek-crease", "d", creasePath("right"));
      setAttr("left-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");
      setAttr("right-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");

      setLayerTransform("head-layer", "");
      setLayerTransform("face-layer", lookActive ? facePlaneTransform(true) : "");
      setLayerTransform("idle-look-blush-clip-wrapper", "");
      setElementTransform("idle-look-blush-transform", lookActive ? blushPlaneTransform() : "");
      setLayerTransform("ears-layer", "");
      setLayerTransform("head-tufts", lookActive ? tuftLookTransform() : "");

      setAttr("left-ear", "transform", lookActive ? translate(ears.left.x, ears.left.y) : "");
      setAttr("right-ear", "transform", lookActive ? translate(ears.right.x, ears.right.y) : "");
      setAttr("left-ear-outer", "r", fmt(lerp(34, 37.4, ears.left.grow)));
      setAttr("left-ear-inner", "r", fmt(lerp(18, 19.8, ears.left.grow)));
      setAttr("right-ear-outer", "r", fmt(lerp(34, 37.4, ears.right.grow)));
      setAttr("right-ear-inner", "r", fmt(lerp(18, 19.8, ears.right.grow)));

      setAttr("left-eye", "rx", "12.5");
      setAttr("right-eye", "rx", "12.5");
      setAttr("left-eye", "ry", "17");
      setAttr("right-eye", "ry", "17");
      setAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, elem.leftEye.dx, elem.leftEye.dy));
      setAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, elem.rightEye.dx, elem.rightEye.dy));
      setAttr("left-brow", "transform", "");
      setAttr("right-brow", "transform", "");
      setAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, elem.leftBlush.dx, elem.leftBlush.dy, elem.leftBlush.sx, elem.leftBlush.sy));
      setAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, elem.rightBlush.dx, elem.rightBlush.dy, elem.rightBlush.sx, elem.rightBlush.sy));
      applySunglassesLook();
      applySunglassesManualTransform();
      setAttr("nose-mouth", "transform", "");
      applyHeadFrameTransform();
    }

function applyHeadFrameTransform() {
      const angle = state.head.angle || 0;
      if (Math.abs(angle) < 1e-6) {
        headFrameLayer.removeAttribute("transform");
        return;
      }
      headFrameLayer.setAttribute(
        "transform",
        `translate(${HEAD_FRAME_PIVOT.x} ${HEAD_FRAME_PIVOT.y}) rotate(${fmt(angle)}) translate(-${HEAD_FRAME_PIVOT.x} -${HEAD_FRAME_PIVOT.y})`
      );
    }

function setAttr(id, name, value) {
      const node = masterLayer.querySelector(`#${id}`) || stageSvg.querySelector(`#${id}`);
      if (!node) return;
      if (value === null || value === undefined || value === "") node.removeAttribute(name);
      else node.setAttribute(name, value);
    }

function setLayerTransform(id, value) {
      setAttr(id, "transform", value);
    }

function setElementTransform(id, value) {
      setAttr(id, "transform", value);
    }

function headLookActive() {
      return Math.abs(state.head.yaw) > .001 || Math.abs(state.head.pitch) > .001;
    }

function axisT(value) {
      return smooth01(Math.abs(value) / 100);
    }

function diagonalFactor() {
      return Math.abs(state.head.yaw) / 100 * Math.abs(state.head.pitch) / 100;
    }

function trimmed(value, trimScale = 1) {
      const trim = 1 - diagonalFactor() * 15 / 100 * trimScale;
      return value * trim;
    }

function smoothRange(start, end, value) {
      return smooth01(clamp((value - start) / (end - start), 0, 1));
    }

function mixPoint(a, b, t) {
      return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
    }

function interpolateNumberString(from, to, t) {
      const a = numbers(from);
      const b = numbers(to);
      let index = 0;
      if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
      return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(lerp(a[index], b[index++] ?? a[index - 1], t)));
    }

function transformTopPoint(point, dir) {
      const axisX = dir < 0 ? 125 : 249;
      const axisTravel = (axisX - VIEW_W / 2) * .75;
      const localX = point.x - axisX;
      const next = { x: axisTravel + axisX + localX, y: point.y };
      const a = rawAnchors.A || { x: 65 };
      const g = rawAnchors.G || { x: 309 };
      const weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
      const weight = Math.pow(Math.sin(Math.PI * weightT), .9);
      return {
        x: point.x + (next.x - point.x) * weight,
        y: point.y
      };
    }

function catmullPath(points, tension = .72, sharpness = .34) {
      const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
      for (let i = 0; i < points.length - 1; i += 1) {
        const p0 = points[Math.max(0, i - 1)];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = points[Math.min(points.length - 1, i + 2)];
        const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
        const localTension = tension * (nearBridge ? (1 - sharpness * .42) : 1);
        const c1 = {
          x: p1.x + (p2.x - p0.x) * localTension / 6,
          y: p1.y + (p2.y - p0.y) * localTension / 6
        };
        const c2 = {
          x: p2.x - (p3.x - p1.x) * localTension / 6,
          y: p2.y - (p3.y - p1.y) * localTension / 6
        };
        segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
      }
      return segs.join(" ");
    }

function yawFacePath() {
      const dir = Math.sign(state.head.yaw);
      const t = axisT(state.head.yaw);
      if (!dir || t <= .001 || TOP_CHAIN.some((id) => !rawAnchors[id])) return BASE_HEAD.cheekD;
      const top = TOP_CHAIN.map((id) => {
        const start = rawAnchors[id];
        const end = transformTopPoint(start, dir);
        return { id, ...mixPoint(start, end, t) };
      });
      const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
      const tail = FRONT_TAIL.map((seg, index) => {
        const mixed = seg.map((value, numberIndex) => lerp(value, sideTail[index][numberIndex], t));
        return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
      }).join(" ");
      return `${catmullPath(top)} ${tail}Z`;
    }

function faceLowerEffect() {
      if (state.head.pitch <= 0) return 0;
      return axisT(state.head.pitch) * lerp(.45, 1, axisT(state.head.yaw));
    }

function faceLowerWrappedPoint(point) {
      const effect = faceLowerEffect();
      if (effect <= .001) return point;
      const lower = smoothRange(238, 263, point.y);
      if (lower <= .001) return point;
      const side = Math.sign(point.x - 187);
      return {
        x: point.x + side * 6 * effect * lower * .3,
        y: point.y + 12 * effect * lower
      };
    }

function faceLowerWrappedPath(path) {
      return transformPathPairs(path, faceLowerWrappedPoint);
    }

function pitchDeltaY(y) {
      if (state.head.pitch === 0) return 0;
      const sign = Math.sign(state.head.pitch);
      const t = axisT(state.head.pitch);
      const lowerWeight = clamp((y - 166) / 92, 0, 1);
      if (sign < 0) return lerp(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
      return lerp(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
    }

function warpPathForPitch(path) {
      let index = 0;
      return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
        const n = Number(value);
        const next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
        index += 1;
        return fmt(next);
      });
    }

function cheekPath() {
      return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
    }

function headCapPath() {
      const yawT = axisT(state.head.yaw);
      const dir = Math.sign(state.head.yaw);
      const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
      const yawPath = dir ? interpolateNumberString(BASE_HEAD.headCapD, yawTarget, yawT) : BASE_HEAD.headCapD;
      let index = 0;
      return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
        const n = Number(value);
        if (index % 2 === 0) {
          index += 1;
          return fmt(n);
        }
        const topWeight = clamp((120 - n) / 80, 0, 1);
        const sideWeight = clamp((n - 120) / 70, 0, 1);
        const sign = Math.sign(state.head.pitch);
        const t = axisT(state.head.pitch);
        const delta = sign < 0
          ? (2 * topWeight - 5.61 * sideWeight) * t
          : (-1.87 * topWeight + 7.28 * sideWeight) * t;
        index += 1;
        return fmt(n + delta);
      });
    }

function creasePath(side) {
      const isLeft = side === "left";
      const base = BASE_HEAD[isLeft ? "leftCreaseD" : "rightCreaseD"];
      const sideSign = isLeft ? 1 : -1;
      const startX = isLeft ? 62 : 312;
      const baseLength = 38;
      const yawT = axisT(state.head.yaw);
      const yawPull = Math.sign(state.head.yaw) * yawT;
      const pitchT = axisT(state.head.pitch);
      return transformPathPairs(base, (point) => {
        const along = isLeft
          ? clamp((point.x - 62) / baseLength, 0, 1)
          : clamp((312 - point.x) / baseLength, 0, 1);
        let next = {
          x: startX + (point.x - startX),
          y: point.y
        };
        next.x += yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along);
        next.x += sideSign * lerp(1.8, 2.4, along) * pitchT;
        next.y += pitchDeltaY(point.y);
        return faceLowerWrappedPoint(next);
      });
    }

function facePlaneTransform(withPitchScale) {
      const dir = Math.sign(state.head.yaw);
      const yawT = axisT(state.head.yaw);
      const axis = 187 + dir * 62 * yawT;
      const dx = dir * 46.5 * yawT;
      const pitchSign = Math.sign(state.head.pitch);
      const pitchT = axisT(state.head.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const dy = trimmed(pitchData.faceDy * pitchT, .45);
      const sy = withPitchScale ? lerp(1, pitchData.faceSy, pitchT) : 1;
      return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 ${fmt(sy)}) translate(${fmt(-axis)} -172)`;
    }

function blushPlaneTransform() {
      const dir = Math.sign(state.head.yaw);
      const yawT = axisT(state.head.yaw);
      const axis = 187 + dir * 62 * yawT;
      const dx = dir * 46.5 * yawT;
      const pitchSign = Math.sign(state.head.pitch);
      const pitchT = axisT(state.head.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const dy = trimmed(pitchData.blushDy * pitchT, .35);
      return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
    }

function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
      if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
      return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
    }

function elementOffsets() {
      const dir = Math.sign(state.head.yaw);
      const yawT = axisT(state.head.yaw);
      const pitchSign = Math.sign(state.head.pitch);
      const pitchT = axisT(state.head.pitch);
      const pitchUp = pitchSign < 0;
      const pitchEye = pitchUp ? -.56 * pitchT : 0;
      const pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
      const yawLeftEye = dir < 0 ? -2 * yawT : 0;
      const yawRightEye = dir > 0 ? 2 * yawT : 0;
      const leftBlushYaw = dir < 0
        ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
        : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
      const rightBlushYaw = dir < 0
        ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
        : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
      return {
        leftEye: { dx: yawLeftEye, dy: pitchEye },
        rightEye: { dx: yawRightEye, dy: pitchEye },
        leftBlush: {
          dx: leftBlushYaw.dx + pitchBlushDx,
          dy: leftBlushYaw.dy,
          sx: leftBlushYaw.sx,
          sy: leftBlushYaw.sy
        },
        rightBlush: {
          dx: rightBlushYaw.dx - pitchBlushDx,
          dy: rightBlushYaw.dy,
          sx: rightBlushYaw.sx,
          sy: rightBlushYaw.sy
        }
      };
    }

function earState() {
      const dir = Math.sign(state.head.yaw);
      const yawT = axisT(state.head.yaw);
      const pitchSign = Math.sign(state.head.pitch);
      const pitchT = axisT(state.head.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const pitchDy = pitchData.earDy * pitchT;
      const left = { x: 0, y: pitchDy, grow: 0 };
      const right = { x: 0, y: pitchDy, grow: 0 };
      if (dir < 0) {
        left.x += -3.5 * yawT;
        left.y += 3.5 * yawT;
        right.grow = smoothRange(.12, 1, yawT);
      } else if (dir > 0) {
        right.x += -9.5 * yawT;
        right.y += 3.5 * yawT;
        left.grow = smoothRange(.12, 1, yawT);
      }
      return { left, right };
    }

function tuftLookTransform() {
      const dir = Math.sign(state.head.yaw);
      const yawT = axisT(state.head.yaw);
      const pitchSign = Math.sign(state.head.pitch);
      const pitchT = axisT(state.head.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
      const pitchDy = pitchData.tuftDy * pitchT;
      return translate(yawDx, pitchDy);
    }

function applySunglassesLook() {
      const screenLook = smoothRange(35, 72, Math.abs(state.head.pitch));
      const scanT = clamp((state.head.yaw + 100) / 200, 0, 1);
      const shineDx = lerp(-3.8, 4.2, scanT) * screenLook;
      const shineDy = lerp(0.8, -0.35, scanT) * screenLook;
      const shineTransform = translate(shineDx, shineDy);
      const shimmer = screenLook * (0.55 + 0.45 * Math.sin(scanT * Math.PI));
      const mainOpacity = fmt(0.10 + shimmer * 0.07);
      const smallOpacity = fmt(0.07 + shimmer * 0.05);

      ["left-lens-main-shine", "right-lens-main-shine"].forEach((id) => {
        setAttr(id, "transform", shineTransform);
        setAttr(id, "opacity", mainOpacity);
      });
      ["left-lens-small-shine", "right-lens-small-shine"].forEach((id) => {
        setAttr(id, "transform", shineTransform);
        setAttr(id, "opacity", smallOpacity);
      });
    }

function applySunglassesManualTransform() {
      const g = state.glasses || defaults.glasses;
      const unchanged = Math.abs(g.x) < 1e-6
        && Math.abs(g.y) < 1e-6
        && Math.abs(g.rotate) < 1e-6
        && Math.abs(g.scale - 1) < 1e-6;
      if (unchanged) {
        setAttr("sunglasses", "transform", "");
        return;
      }
      setAttr(
        "sunglasses",
        "transform",
        `translate(${fmt(187 + g.x)} ${fmt(157 + g.y)}) rotate(${fmt(g.rotate)}) scale(${fmt(g.scale)}) translate(-187 -157)`
      );
    }

function translate(x, y) {
      return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
    }

function transformPathPairs(path, fn) {
      const values = numbers(path);
      const output = [];
      for (let i = 0; i < values.length; i += 2) {
        const point = fn({ x: values[i], y: values[i + 1] });
        output.push(point.x, point.y);
      }
      let index = 0;
      return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
    }

function smooth01(value) {
      const t = clamp(value, 0, 1);
      return t * t * (3 - 2 * t);
    }

function clamp(value, min, max) {
      return Math.max(min, Math.min(max, value));
    }

function lerp(a, b, t) {
      return a + (b - a) * t;
    }

function fmt(value) {
      if (!Number.isFinite(value)) return "0";
      return String(parseFloat(value.toFixed(3)));
    }

function numbers(value) {
      return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
    }

function mergeState(base, patch) {
      for (const key of Object.keys(base)) {
        if (!patch || typeof patch[key] !== "object") continue;
        base[key] = { ...base[key], ...patch[key] };
      }
      return base;
    }

function clone(value) {
      return JSON.parse(JSON.stringify(value));
    }
})();
